#include <stdio.h>
#include <stdbool.h>
#define MAX_LEN 1005

bool isValid(const char *s){
    char stack[MAX_LEN];
    int top=-1;
    for(int i=0;s[i]!='\0';++i){
        char c=s[i];
        if(c=='('||c=='{'||c=='['){
            stack[++top]=c;
        }else{
            if(top==-1) return false;
            if((c==')'&&stack[top]!='(')||
               (c=='}'&&stack[top]!='{')||
               (c==']'&&stack[top]!='[')) return false;
            --top;
        }
    }
    return top==-1;
}

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    char buf[MAX_LEN];
    while(T--){
        if(scanf("%s",buf)!=1) break;
        printf("%s\n",isValid(buf)?"true":"false");
    }
    return 0;
}

